#include <bits/stdc++.h>
using namespace std;

long long comparisons = 0;
long long shifts = 0;

// Helper functions for dataset generation
vector<int> generateBestCase(int n) { 
    vector<int> arr(n); 
    for(int i=0; i<n; i++) arr[i] = i+1; 
    return arr; 
}

vector<int> generateWorstCase(int n) { 
    vector<int> arr(n); 
    for(int i=0; i<n; i++) arr[i] = n-i; 
    return arr; 
}

vector<int> generateAverageCase(int n) { 
    vector<int> arr(n); 
    for(int i=0; i<n; i++) arr[i] = rand() % 10000; 
    return arr; 
}

// Insertion Sort with metrics & visualization
void insertionSort(vector<int>& arr) {
    int n = arr.size();
    // Initial state recorded here by backend
    for(int i=1; i<n; i++) {
        int key = arr[i];
        int j = i-1;
        while(++comparisons && j>=0 && arr[j]>key) {
            arr[j+1] = arr[j];
            shifts++;
            j--;
        }
        arr[j+1] = key;
        // Snapshot of each iteration recorded here by backend
    }
}

int main() {
    int n;
    string case_type = "average"; // Injected by backend

    if (!(cin >> n)) return 0;

    vector<int> arr;
    if(case_type == "best") arr = generateBestCase(n);
    else if(case_type == "worst") arr = generateWorstCase(n);
    else arr = generateAverageCase(n);

    comparisons = 0; shifts = 0;

    insertionSort(arr);

    // Output metrics for backend parsing
    cout << "__metrics__ " << comparisons << " " << shifts << endl;

    return 0;
}
